package ranking

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"math"
	"strconv"
	"strings"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
)

// Opinion represents a single ranking observation for one institution from one
// publication/category in a given year.
type Opinion struct {
	PublicationSlug string
	CategorySlug    string
	Method          string  // "rank", "score", "tier", "range"
	Year            int
	UnitID          string
	Rank            int
	Score           float64
	Tier            string
}

// PublicationMeta holds display metadata for a ranking publication+category.
type PublicationMeta struct {
	PublicationSlug string
	Publication     string // display name
	CategorySlug    string
	Category        string // display name
	URL             string
}

// rankingID returns the deterministic key used across ranking tables and the
// institution JSONB column. Format: "pub_slug____cat_slug".
func rankingID(pubSlug, catSlug string) string {
	return pubSlug + "____" + catSlug
}

// RankingBuilder accumulates Opinion values and publication metadata, then
// batch-writes them to the database via Flush.
type RankingBuilder struct {
	opinions     []Opinion
	publications map[string]PublicationMeta // keyed by rankingID
}

// NewBuilder creates an empty RankingBuilder.
func NewBuilder() *RankingBuilder {
	return &RankingBuilder{
		publications: make(map[string]PublicationMeta),
	}
}

// SetPublication registers display metadata for a publication+category pair.
func (b *RankingBuilder) SetPublication(pubSlug, pubName, catSlug, catName, url string) {
	id := rankingID(pubSlug, catSlug)
	b.publications[id] = PublicationMeta{
		PublicationSlug: pubSlug,
		Publication:     pubName,
		CategorySlug:    catSlug,
		Category:        catName,
		URL:             url,
	}
}

// Add appends an opinion to the builder.
func (b *RankingBuilder) Add(op Opinion) {
	b.opinions = append(b.opinions, op)
}

// Len returns the number of accumulated opinions.
func (b *RankingBuilder) Len() int {
	return len(b.opinions)
}

// Flush writes all accumulated data to the database:
//  1. Upserts ranking metadata into search_base.ranking
//  2. Upserts per-year data into search_base.annual_dataset (theme=RANKING)
//  3. Merges latest-year rankings into institution.rankings JSONB
func (b *RankingBuilder) Flush(ctx context.Context, pool *pgxpool.Pool) error {
	if len(b.opinions) == 0 {
		return nil
	}

	// Step 1: upsert ranking metadata
	if err := b.flushRankingMeta(ctx, pool); err != nil {
		return err
	}

	// Step 2: upsert annual datasets
	if err := b.flushAnnualDatasets(ctx, pool); err != nil {
		return err
	}

	// Step 3: merge into institution.rankings JSONB
	if err := b.flushInstitutionRankings(ctx, pool); err != nil {
		return err
	}

	slog.Info("ranking: flushed", "opinions", len(b.opinions), "publications", len(b.publications))
	return nil
}

func (b *RankingBuilder) flushRankingMeta(ctx context.Context, pool *pgxpool.Pool) error {
	const upsertSQL = `
INSERT INTO search_base.ranking (id, publication_slug, publication, category_slug, category, url)
VALUES ($1, $2, $3, $4, $5, $6)
ON CONFLICT (id) DO UPDATE SET
    publication = EXCLUDED.publication,
    category    = EXCLUDED.category,
    url         = EXCLUDED.url`

	queries := make([]dbutil.BatchQuery, 0, len(b.publications))
	for id, pm := range b.publications {
		queries = append(queries, dbutil.BatchQuery{
			SQL:  upsertSQL,
			Args: []any{id, pm.PublicationSlug, pm.Publication, pm.CategorySlug, pm.Category, pm.URL},
		})
	}
	if err := dbutil.BatchExec(ctx, pool, queries); err != nil {
		return fmt.Errorf("ranking: flush ranking meta: %w", err)
	}
	return nil
}

func (b *RankingBuilder) flushAnnualDatasets(ctx context.Context, pool *pgxpool.Pool) error {
	const batchSize = 500
	for i := 0; i < len(b.opinions); i += batchSize {
		end := i + batchSize
		if end > len(b.opinions) {
			end = len(b.opinions)
		}
		if err := b.flushAnnualDatasetBatch(ctx, pool, b.opinions[i:end]); err != nil {
			return err
		}
	}
	return nil
}

func (b *RankingBuilder) flushAnnualDatasetBatch(ctx context.Context, pool *pgxpool.Pool, opinions []Opinion) error {
	for _, op := range opinions {
		data := buildOpinionData(op)
		dataJSON, err := json.Marshal(data)
		if err != nil {
			return fmt.Errorf("ranking: marshal annual dataset: %w", err)
		}
		ads := &dbutil.AnnualDataset{
			UnitID:  op.UnitID,
			Year:    op.Year,
			Theme:   "RANKING",
			Datakey: rankingID(op.PublicationSlug, op.CategorySlug),
			Data:    dataJSON,
		}
		if err := dbutil.UpsertAnnualDataset(ctx, pool, ads); err != nil {
			return fmt.Errorf("ranking: flush annual dataset: %w", err)
		}
	}
	return nil
}

// buildOpinionData returns the JSONB payload for an opinion.
func buildOpinionData(op Opinion) map[string]any {
	d := map[string]any{
		"method": op.Method,
	}
	switch op.Method {
	case "rank":
		d["rank"] = op.Rank
	case "score":
		d["score"] = op.Score
	case "tier":
		d["tier"] = op.Tier
	case "range":
		d["rank"] = op.Rank
		d["tier"] = op.Tier
	}
	return d
}

func (b *RankingBuilder) flushInstitutionRankings(ctx context.Context, pool *pgxpool.Pool) error {
	// Group opinions by unit_id, keeping only the latest year per ranking.
	type key struct {
		unitID    string
		rankingID string
	}
	latest := make(map[key]Opinion)
	for _, op := range b.opinions {
		k := key{unitID: op.UnitID, rankingID: rankingID(op.PublicationSlug, op.CategorySlug)}
		if existing, ok := latest[k]; !ok || op.Year > existing.Year {
			latest[k] = op
		}
	}

	// Group by unit_id to build per-institution JSONB.
	byUnit := make(map[string]map[string]any)
	for k, op := range latest {
		if byUnit[k.unitID] == nil {
			byUnit[k.unitID] = make(map[string]any)
		}
		byUnit[k.unitID][k.rankingID] = buildOpinionData(op)
	}

	for unitID, rankings := range byUnit {
		rankingsJSON, err := json.Marshal(rankings)
		if err != nil {
			return fmt.Errorf("ranking: marshal institution rankings: %w", err)
		}
		inst := &dbutil.Institution{
			UnitID:   unitID,
			Rankings: rankingsJSON,
		}
		if err := dbutil.UpsertInstitution(ctx, pool, inst); err != nil {
			return fmt.Errorf("ranking: flush institution rankings: %w", err)
		}
	}
	return nil
}

// DeriveOpinion parses a raw ranking string and returns the method, rank,
// score, and tier. Supported formats:
//   - Numeric ranks: "1", "42"
//   - Tier strings: "Tier 1", "Tier 2"
//   - Ranges: "201-300" (rank = midpoint, tier = original string)
//   - Decimal scores: "78.5"
func DeriveOpinion(raw string) (method string, rank int, score float64, tier string, err error) {
	raw = strings.TrimSpace(raw)
	if raw == "" {
		return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: empty input")
	}

	// Tier format: "Tier N" or "Tier ..."
	if strings.HasPrefix(strings.ToLower(raw), "tier") {
		return "tier", 0, 0, raw, nil
	}

	// Range format: "NNN-NNN"
	if parts := strings.SplitN(raw, "-", 2); len(parts) == 2 {
		lo, errLo := strconv.Atoi(strings.TrimSpace(parts[0]))
		hi, errHi := strconv.Atoi(strings.TrimSpace(parts[1]))
		if errLo == nil && errHi == nil && lo > 0 && hi > 0 {
			midpoint := int(math.Round(float64(lo+hi) / 2))
			return "range", midpoint, 0, raw, nil
		}
	}

	// Integer rank
	if n, errInt := strconv.Atoi(raw); errInt == nil {
		return "rank", n, 0, "", nil
	}

	// Decimal score
	if f, errFloat := strconv.ParseFloat(raw, 64); errFloat == nil {
		return "score", 0, f, "", nil
	}

	return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: unrecognized format %q", raw)
}

