			return fmt.Errorf("ranking: marshal annual dataset: %w", err)
		}
		ads := &dbutil.AnnualDataset{
			UnitID:  op.UnitID,
			Year:    op.Year,
			Theme:   "RANKING",
			Datakey: rankingID(op.PublicationSlug, op.CategorySlug),
			Data:    dataJSON,
		}
		if err := dbutil.UpsertAnnualDataset(ctx, pool, ads); err != nil {
			return fmt.Errorf("ranking: flush annual dataset: %w", err)
		}
	}
	return nil
}

// buildOpinionData returns the JSONB payload for an opinion.
func buildOpinionData(op Opinion) map[string]any {
	d := map[string]any{
		"method": op.Method,
	}
	switch op.Method {
	case "rank":
		d["rank"] = op.Rank
	case "score":
		d["score"] = op.Score
	case "tier":
		d["tier"] = op.Tier
	case "range":
		d["rank"] = op.Rank
		d["tier"] = op.Tier
	}
	return d
}

func (b *RankingBuilder) flushInstitutionRankings(ctx context.Context, pool *pgxpool.Pool) error {
	// Group opinions by unit_id, keeping only the latest year per ranking.
	type key struct {
		unitID    string
		rankingID string
	}
	latest := make(map[key]Opinion)
	for _, op := range b.opinions {
		k := key{unitID: op.UnitID, rankingID: rankingID(op.PublicationSlug, op.CategorySlug)}
		if existing, ok := latest[k]; !ok || op.Year > existing.Year {
			latest[k] = op
		}
	}

	// Group by unit_id to build per-institution JSONB.
	byUnit := make(map[string]map[string]any)
	for k, op := range latest {
		if byUnit[k.unitID] == nil {
			byUnit[k.unitID] = make(map[string]any)
		}
		byUnit[k.unitID][k.rankingID] = buildOpinionData(op)
	}

	for unitID, rankings := range byUnit {
		rankingsJSON, err := json.Marshal(rankings)
		if err != nil {
			return fmt.Errorf("ranking: marshal institution rankings: %w", err)
		}
		inst := &dbutil.Institution{
			UnitID:   unitID,
			Rankings: rankingsJSON,
		}
		if err := dbutil.UpsertInstitution(ctx, pool, inst); err != nil {
			return fmt.Errorf("ranking: flush institution rankings: %w", err)
		}
	}
	return nil
}

// DeriveOpinion parses a raw ranking string and returns the method, rank,
// score, and tier. Supported formats:
//   - Numeric ranks: "1", "42"
//   - Tier strings: "Tier 1", "Tier 2"
//   - Ranges: "201-300" (rank = midpoint, tier = original string)
//   - Decimal scores: "78.5"
func DeriveOpinion(raw string) (method string, rank int, score float64, tier string, err error) {
	raw = strings.TrimSpace(raw)
	if raw == "" {
		return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: empty input")
	}

	// Tier format: "Tier N" or "Tier ..."
	if strings.HasPrefix(strings.ToLower(raw), "tier") {
		return "tier", 0, 0, raw, nil
	}

	// Range format: "NNN-NNN"
	if parts := strings.SplitN(raw, "-", 2); len(parts) == 2 {
		lo, errLo := strconv.Atoi(strings.TrimSpace(parts[0]))
		hi, errHi := strconv.Atoi(strings.TrimSpace(parts[1]))
		if errLo == nil && errHi == nil && lo > 0 && hi > 0 {
			midpoint := int(math.Round(float64(lo+hi) / 2))
			return "range", midpoint, 0, raw, nil
		}
	}

	// Integer rank
	if n, errInt := strconv.Atoi(raw); errInt == nil {
		return "rank", n, 0, "", nil
	}

	// Decimal score
	if f, errFloat := strconv.ParseFloat(raw, 64); errFloat == nil {
		return "score", 0, f, "", nil
	}

	return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: unrecognized format %q", raw)
}

