func TestDeriveOpinion(t *testing.T) {
	tests := []struct {
		raw        string
		wantMethod string
		wantRank   int
		wantScore  float64
		wantTier   string
		wantErr    bool
	}{
		// Numeric ranks
		{raw: "1", wantMethod: "rank", wantRank: 1},
		{raw: "42", wantMethod: "rank", wantRank: 42},
		{raw: " 15 ", wantMethod: "rank", wantRank: 15},

		// Tier strings
		{raw: "Tier 1", wantMethod: "tier", wantTier: "Tier 1"},
		{raw: "Tier 2", wantMethod: "tier", wantTier: "Tier 2"},
		{raw: "tier 3", wantMethod: "tier", wantTier: "tier 3"},

		// Ranges
		{raw: "201-300", wantMethod: "range", wantRank: 251, wantTier: "201-300"},
		{raw: "1-10", wantMethod: "range", wantRank: 6, wantTier: "1-10"},
		{raw: "100-200", wantMethod: "range", wantRank: 150, wantTier: "100-200"},

		// Decimal scores
		{raw: "78.5", wantMethod: "score", wantScore: 78.5},
		{raw: "99.9", wantMethod: "score", wantScore: 99.9},

		// Errors
		{raw: "", wantErr: true},
		{raw: "N/A", wantErr: true},
		{raw: "not ranked", wantErr: true},
	}

	for _, tt := range tests {
		t.Run(tt.raw, func(t *testing.T) {
			method, rank, score, tier, err := DeriveOpinion(tt.raw)
			if tt.wantErr {
				if err == nil {
					t.Fatalf("expected error for %q, got method=%q", tt.raw, method)
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error for %q: %v", tt.raw, err)
			}
			if method != tt.wantMethod {
				t.Errorf("method: got %q, want %q", method, tt.wantMethod)
			}
			if rank != tt.wantRank {
				t.Errorf("rank: got %d, want %d", rank, tt.wantRank)
			}
			if score != tt.wantScore {
				t.Errorf("score: got %f, want %f", score, tt.wantScore)
			}
			if tier != tt.wantTier {
				t.Errorf("tier: got %q, want %q", tier, tt.wantTier)
			}
		})
	}
}

