func TestRankingID(t *testing.T) {
	got := rankingID("us_news", "national_universities")
	want := "us_news____national_universities"
	if got != want {
		t.Errorf("rankingID: got %q, want %q", got, want)
	}

	got = rankingID("forbes", "")
	want = "forbes____"
	if got != want {
		t.Errorf("rankingID empty cat: got %q, want %q", got, want)
	}
}

func TestBuildOpinionData(t *testing.T) {
	tests := []struct {
		name string
		op   Opinion
		want map[string]any
	}{
		{
			name: "rank",
			op:   Opinion{Method: "rank", Rank: 15},
			want: map[string]any{"method": "rank", "rank": 15},
		},
		{
			name: "score",
			op:   Opinion{Method: "score", Score: 78.5},
			want: map[string]any{"method": "score", "score": 78.5},
		},
		{
			name: "tier",
			op:   Opinion{Method: "tier", Tier: "Tier 1"},
			want: map[string]any{"method": "tier", "tier": "Tier 1"},
		},
		{
			name: "range",
			op:   Opinion{Method: "range", Rank: 250, Tier: "201-300"},
			want: map[string]any{"method": "range", "rank": 250, "tier": "201-300"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := buildOpinionData(tt.op)

			// Compare via JSON round-trip to handle int/float type differences.
			gotJSON, _ := json.Marshal(got)
			wantJSON, _ := json.Marshal(tt.want)

			var gotMap, wantMap map[string]any
			json.Unmarshal(gotJSON, &gotMap)
			json.Unmarshal(wantJSON, &wantMap)

			if len(gotMap) != len(wantMap) {
				t.Fatalf("key count: got %d, want %d\ngot:  %s\nwant: %s", len(gotMap), len(wantMap), gotJSON, wantJSON)
			}
			for k, wv := range wantMap {
				gv, ok := gotMap[k]
				if !ok {
					t.Errorf("missing key %q", k)
					continue
				}
				if fmt(gv) != fmt(wv) {
					t.Errorf("key %q: got %v, want %v", k, gv, wv)
				}
			}
		})
	}
}

// fmt formats a value for comparison — handles json.Number differences.
func fmt(v any) string {
	b, _ := json.Marshal(v)
	return string(b)
}

